@js:
if(!baseUrl.match(/_/)){
	if(result.match(/第\d+\/\d+页/)){
	num=result.match(/第\d+\/(\d+)页/)[1]
	for(var i=1,txt=[];i-num<0;i++){
		txt.push(baseUrl.replace(/\.html/,'_'+i+'\.html'))
		}
		txt.join("\r\n")
		}
	}

